// Format error details for notification
const errorData = $input.first().json;

const workflowName = errorData.workflow?.name || 'Unknown Workflow';
const executionId = errorData.execution?.id || 'N/A';
const errorMessage = errorData.execution?.error?.message || 'No error message';
const errorNode = errorData.execution?.lastNodeExecuted || 'Unknown';
const timestamp = new Date().toISOString();

// Build formatted message
const message = [
  `🚨 **Workflow Failure Alert**`,
  ``,
  `**Workflow:** ${workflowName}`,
  `**Execution ID:** ${executionId}`,
  `**Failed Node:** ${errorNode}`,
  `**Error:** ${errorMessage}`,
  `**Timestamp:** ${timestamp}`,
  ``,
  `Check n8n executions for full details.`
].join('\n');

return [{
  json: {
    text: message,
    workflow_name: workflowName,
    execution_id: executionId,
    error_message: errorMessage,
    error_node: errorNode,
    timestamp: timestamp
  }
}];

// Log error locally when no notification channel is configured
console.log('ERROR LOGGED (no notification channel configured):');
console.log(JSON.stringify($json, null, 2));

return [{ json: { status: 'logged_locally', ...$json } }];
